{"content":"1: package ualert
2: 
3: import (
4: 	"fmt"
5: 	"os"
6: 	"path/filepath"
7: 	"strconv"
8: 
9: 	"github.com/grafana/grafana/pkg/util/xorm"
10: 
11: 	ngmodels "github.com/grafana/grafana/pkg/services/ngalert/models"
12: 	"github.com/grafana/grafana/pkg/services/sqlstore/migrator"
13: )
14: 
15: var migTitle = "move dashboard alerts to unified alerting"
16: 
17: const codeMigration = "code migration"
18: 
19: type MigrationError struct {
20: 	AlertId int64
21: 	Err     error
22: }
23: 
24: func (e MigrationError) Error() string {
25: 	return fmt.Sprintf("failed to migrate alert %d: %s", e.AlertId, e.Err.Error())
26: }
27: 
28: func (e *MigrationError) Unwrap() error { return e.Err }
29: 
30: // FixEarlyMigration fixes UA configs created before 8.2 with org_id=0 and moves some files like __default__.tmpl.
31: // The only use of this migration is when a user enabled ng-alerting before 8.2.
32: func FixEarlyMigration(mg *migrator.Migrator) {
33: 	cloneMigTitle := fmt.Sprintf("clone %s", migTitle)
34: 	mg.AddMigration(cloneMigTitle, &upgradeNgAlerting{})
35: }
36: 
37: func AddDashboardUIDPanelIDMigration(mg *migrator.Migrator) {
38: 	migrationID := "update dashboard_uid and panel_id from existing annotations"
39: 	mg.AddMigration(migrationID, &updateDashboardUIDPanelIDMigration{})
40: }
41: 
42: // updateDashboardUIDPanelIDMigration sets the dashboard_uid and panel_id columns
43: // from the __dashboardUid__ and __panelId__ annotations.
44: type updateDashboardUIDPanelIDMigration struct {
45: 	migrator.MigrationBase
46: }
47: 
48: func (m *updateDashboardUIDPanelIDMigration) SQL(_ migrator.Dialect) string {
49: 	return "set dashboard_uid and panel_id migration"
50: }
51: 
52: func (m *updateDashboardUIDPanelIDMigration) Exec(sess *xorm.Session, mg *migrator.Migrator) error {
53: 	var results []struct {
54: 		ID          int64             `xorm:"id"`
55: 		Annotations map[string]string `xorm:"annotations"`
56: 	}
57: 	if err := sess.SQL(`SELECT id, annotations FROM alert_rule`).Find(&results); err != nil {
58: 		return fmt.Errorf("failed to get annotations for all alert rules: %w", err)
59: 	}
60: 	for _, next := range results {
61: 		var (
62: 			dashboardUID *string
63: 			panelID      *int64
64: 		)
65: 		if s, ok := next.Annotations[ngmodels.DashboardUIDAnnotation]; ok {
66: 			dashboardUID = &s
67: 		}
68: 		if s, ok := next.Annotations[ngmodels.PanelIDAnnotation]; ok {
69: 			i, err := strconv.ParseInt(s, 10, 64)
70: 			if err != nil {
71: 				return fmt.Errorf("the %s annotation does not contain a valid Panel ID: %w", ngmodels.PanelIDAnnotation, err)
72: 			}
73: 			panelID = &i
74: 		}
75: 		// We do not want to set panel_id to a non-nil value when dashboard_uid is nil
76: 		// as panel_id is not unique and so cannot be queried without its dashboard_uid.
77: 		// This can happen where users have deleted the dashboard_uid annotation but kept
78: 		// the panel_id annotation.
79: 		if dashboardUID != nil {
80: 			if _, err := sess.Exec(`UPDATE alert_rule SET dashboard_uid = ?, panel_id = ? WHERE id = ?`,
81: 				dashboardUID,
82: 				panelID,
83: 				next.ID); err != nil {
84: 				return fmt.Errorf("failed to set dashboard_uid and panel_id for alert rule: %w", err)
85: 			}
86: 		}
87: 	}
88: 	return nil
89: }
90: 
91: type AlertConfiguration struct {
92: 	ID    int64 `xorm:"pk autoincr 'id'"`
93: 	OrgID int64 `xorm:"org_id"`
94: 
95: 	AlertmanagerConfiguration string
96: 	ConfigurationVersion      string
97: 	CreatedAt                 int64 `xorm:"created"`
98: }
99: 
100: type upgradeNgAlerting struct {
101: 	migrator.MigrationBase
102: }
103: 
104: var _ migrator.CodeMigration = &upgradeNgAlerting{}
105: 
106: func (u *upgradeNgAlerting) Exec(sess *xorm.Session, migrator *migrator.Migrator) error {
107: 	firstOrgId, err := u.updateAlertConfigurations(sess, migrator)
108: 	if err != nil {
109: 		return err
110: 	}
111: 	u.updateAlertmanagerFiles(firstOrgId, migrator)
112: 	return nil
113: }
114: 
115: func (u *upgradeNgAlerting) updateAlertConfigurations(sess *xorm.Session, migrator *migrator.Migrator) (int64, error) {
116: 	// if there are records with org_id == 0 then the feature flag was enabled before 8.2 that introduced org separation.
117: 	// if feature is enabled in 8.2 the migration "AddDashAlertMigration", which is effectively different from what was run in 8.1.x and earlier versions,
118: 	// will handle organizations correctly, and, therefore, nothing needs to be fixed
119: 	count, err := sess.Table(&AlertConfiguration{}).Where("org_id = 0").Count()
120: 	if err != nil {
121: 		return 0, fmt.Errorf("failed to query table alert_configuration: %w", err)
122: 	}
123: 	if count == 0 {
124: 		return 0, nil // NOTHING TO DO
125: 	}
126: 
127: 	orgs := make([]int64, 0)
128: 	// get all org IDs sorted in ascending order
129: 	if err = sess.Table("org").OrderBy("id").Cols("id").Find(&orgs); err != nil {
130: 		return 0, fmt.Errorf("failed to query table org: %w", err)
131: 	}
132: 	if len(orgs) == 0 { // should not really happen
133: 		migrator.Logger.Info("No organizations are found. Nothing to migrate")
134: 		return 0, nil
135: 	}
136: 
137: 	firstOrg := orgs[0]
138: 
139: 	// assigning all configurations to the first org because 0 does not usually point to any
140: 	migrator.Logger.Info("Assigning all existing records from alert_configuration to the first organization", "org", firstOrg)
141: 	_, err = sess.Cols("org_id").Where("org_id = 0").Update(&AlertConfiguration{OrgID: firstOrg})
142: 	if err != nil {
143: 		return 0, fmt.Errorf("failed to update org_id for all rows in the table alert_configuration: %w", err)
144: 	}
145: 
146: 	// if there is a single organization it is safe to assume that all configurations belong to it.
147: 	if len(orgs) == 1 {
148: 		return firstOrg, nil
149: 	}
150: 	// if there are many organizations we cannot safely assume what organization an alert_configuration belongs to.
